import{_ as e,o as t,c as o,a0 as r}from"./chunks/framework.jwovEGr5.js";const c=JSON.parse('{"title":"도둑맞은 집중력","description":"","frontmatter":{},"headers":[],"relativePath":"outta-space/knowledge/books/도둑맞은-집중력.md","filePath":"outta-space/knowledge/books/도둑맞은-집중력.md"}'),_={name:"outta-space/knowledge/books/도둑맞은-집중력.md"};function n(l,a,i,s,d,h){return t(),o("div",null,[...a[0]||(a[0]=[r('<h1 id="도둑맞은-집중력" tabindex="-1">도둑맞은 집중력 <a class="header-anchor" href="#도둑맞은-집중력" aria-label="Permalink to &quot;도둑맞은 집중력&quot;">​</a></h1><h2 id="_1-핵심-내용" tabindex="-1">1. 핵심 내용 <a class="header-anchor" href="#_1-핵심-내용" aria-label="Permalink to &quot;1. 핵심 내용&quot;">​</a></h2><p>이 책에서 인상 깊었던 부분은 “알고리즘”이라는 단어의 의미 변화였다. 전통적으로 알고리즘은 문제 해결을 위한 논리적 절차나 프로그램의 흐름을 뜻했지만, 현대 대중적 의미에서는 온라인 플랫폼의 맞춤형 콘텐츠 추천 기능을 가리키는 말로 쓰인다.</p><p>이 변화는 우리가 정보를 접하는 방식이 달라졌다는 것을 보여준다. 이제 우리는 스스로 정보를 찾기보다, 플랫폼이 추천하는 정보 환경 속에서 생각하고 반응한다.</p><h2 id="_2-문체와-가독성" tabindex="-1">2. 문체와 가독성 <a class="header-anchor" href="#_2-문체와-가독성" aria-label="Permalink to &quot;2. 문체와 가독성&quot;">​</a></h2><p>책은 집중력 저하라는 개인적 문제처럼 보이는 주제를 사회적·기술적 구조와 연결해 설명한다. 알고리즘, 플랫폼, 인간 심리 같은 주제를 일상적 경험과 연결해 풀어내기 때문에 비교적 읽기 쉽다.</p><h2 id="_3-저자의-관점과-설득력" tabindex="-1">3. 저자의 관점과 설득력 <a class="header-anchor" href="#_3-저자의-관점과-설득력" aria-label="Permalink to &quot;3. 저자의 관점과 설득력&quot;">​</a></h2><p>저자는 집중력 문제를 개인의 의지 부족으로만 보지 않는다. 추천 알고리즘, 광고 기반 플랫폼, 인간의 부정 편향이 결합된 결과로 설명한다.</p><p>특히 부정적 콘텐츠가 더 많이 노출되는 이유를 알고리즘의 악의가 아니라, 부정적인 정보에 더 강하게 반응하는 인간 심리에 최적화된 결과로 보는 관점이 설득력 있었다.</p><h2 id="_4-인상-깊은-부분" tabindex="-1">4. 인상 깊은 부분 <a class="header-anchor" href="#_4-인상-깊은-부분" aria-label="Permalink to &quot;4. 인상 깊은 부분&quot;">​</a></h2><p>가장 인상 깊었던 부분은 부정적 콘텐츠 노출의 책임을 개인에게만 돌릴 수 있는가에 대한 의문이었다.</p><p>사회적·기술적 구조가 사람의 주의를 빼앗도록 설계되어 있다면, 문제 해결을 개인의 자기 절제에만 맡기는 것은 공정하지 않다. “안 보면 된다”는 말만으로는 충분하지 않다.</p><h2 id="_5-나에게-남은-생각" tabindex="-1">5. 나에게 남은 생각 <a class="header-anchor" href="#_5-나에게-남은-생각" aria-label="Permalink to &quot;5. 나에게 남은 생각&quot;">​</a></h2><p>이 책을 읽고 집중력 문제를 단순히 개인의 게으름이나 의지 부족으로 볼 수는 없겠다고 생각했다.</p><p>개인의 습관도 중요하지만, 그 습관이 형성되는 정보 환경 역시 함께 봐야 한다. 결국 이 책은 집중력을 되찾기 위해 개인의 노력뿐 아니라 기술과 플랫폼 구조에 대한 비판적 시선이 필요하다는 생각을 남긴다.</p>',15)])])}const u=e(_,[["render",n]]);export{c as __pageData,u as default};
